import{_ as e,a as t}from"./chunks/添加渠道.o1VHzHEI.js";import{_ as d,o as n,c as s,a2 as i}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Додавання каналу Hugging Face","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/huggingface.md","filePath":"uk-UA/upload/huggingface.md","lastUpdated":1781962217000}'),o={name:"uk-UA/upload/huggingface.md"};function r(c,a,g,l,p,h){return n(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="додавання-каналу-hugging-face" tabindex="-1">Додавання каналу Hugging Face <a class="header-anchor" href="#додавання-каналу-hugging-face" aria-label="Permalink to &quot;Додавання каналу Hugging Face&quot;">​</a></h1><h2 id="що-підготувати-заздалегідь" tabindex="-1">Що підготувати заздалегідь <a class="header-anchor" href="#що-підготувати-заздалегідь" aria-label="Permalink to &quot;Що підготувати заздалегідь&quot;">​</a></h2><p>Потрібні лише три речі:</p><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>Обліковий запис Hugging Face</td><td>Для створення access token і володіння репозиторієм.</td></tr><tr><td>Hugging Face User Access Token</td><td>ImgBed використовує його для доступу до Hugging Face API, створення репозиторіїв і завантаження файлів.</td></tr><tr><td>Назва репозиторію</td><td>Можна ввести тільки назву репозиторію, наприклад <code>image</code>.</td></tr></tbody></table><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><h3 id="крок-1-увіидіть-у-hugging-face-і-створіть-access-token" tabindex="-1">Крок 1. Увійдіть у Hugging Face і створіть Access Token <a class="header-anchor" href="#крок-1-увіидіть-у-hugging-face-і-створіть-access-token" aria-label="Permalink to &quot;Крок 1. Увійдіть у Hugging Face і створіть Access Token&quot;">​</a></h3><ol><li>Увійдіть у Hugging Face.</li><li>Натисніть свій аватар у правому верхньому куті й відкрийте <code>Settings</code>.</li><li>У лівій бічній панелі відкрийте <code>Access Tokens</code>.</li><li>Створіть новий token.</li><li>Дайте token зрозумілу назву.</li><li>Виберіть дозвіл <code>write</code>.</li><li>Одразу після створення скопіюйте й збережіть token.</li></ol><p><img src="'+e+'" alt="Створення token" loading="lazy"></p><h2 id="крок-2-заповніть-канал-hugging-face-в-imgbed" tabindex="-1">Крок 2. Заповніть канал Hugging Face в ImgBed <a class="header-anchor" href="#крок-2-заповніть-канал-hugging-face-в-imgbed" aria-label="Permalink to &quot;Крок 2. Заповніть канал Hugging Face в ImgBed&quot;">​</a></h2><p>Після вибору <code>Hugging Face</code> у налаштуваннях завантаження заповніть поля так:</p><table tabindex="0"><thead><tr><th>Поле в інтерфейсі</th><th>Що ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Назва на ваш вибір, наприклад <code>hf-primary</code>.</td></tr><tr><td>Repository name</td><td>Або коротка назва repo, наприклад <code>image</code>, або повний шлях на кшталт <code>username/image</code>.</td></tr><tr><td>Access Token</td><td>Hugging Face User Access Token, який ви щойно створили.</td></tr><tr><td>Private repository</td><td>Увімкніть або вимкніть відповідно до ваших потреб.</td></tr><tr><td>Remark</td><td>Необов&#39;язково, наприклад <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+t+`" alt="Додавання каналу" loading="lazy"></p><h2 id="крок-3-збережіть-канал" tabindex="-1">Крок 3. Збережіть канал <a class="header-anchor" href="#крок-3-збережіть-канал" aria-label="Permalink to &quot;Крок 3. Збережіть канал&quot;">​</a></h2><p>Після заповнення полів натисніть Save.</p><p>Далі система сама обробить такі деталі:</p><table tabindex="0"><thead><tr><th>Поведінка системи</th><th>Опис</th></tr></thead><tbody><tr><td>Коротка назва репозиторію</td><td>ImgBed визначає поточний обліковий запис Hugging Face і розгортає значення до повного шляху репозиторію.</td></tr><tr><td>Повний шлях репозиторію</td><td>ImgBed використовує шлях <code>username/repository</code> саме в тому вигляді, у якому його введено.</td></tr><tr><td>Перевірка репозиторію</td><td>Якщо використовується шлях поточного особистого акаунта, ImgBed спробує створити репозиторій, якщо його ще немає. Якщо повний шлях введено вручну, ImgBed використовує його напряму.</td></tr><tr><td>Тип репозиторію</td><td>Цей канал використовує репозиторій типу <code>dataset</code>.</td></tr><tr><td>Публічний або приватний стан</td><td>Видимість репозиторію синхронізується відповідно до поточного перемикача.</td></tr></tbody></table><h2 id="короткии-чекліст" tabindex="-1">Короткий чекліст <a class="header-anchor" href="#короткии-чекліст" aria-label="Permalink to &quot;Короткий чекліст&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Увійти в Hugging Face</span></span>
<span class="line"><span>-&gt; Створити Access Token</span></span>
<span class="line"><span>-&gt; Вибрати дозвіл write</span></span>
<span class="line"><span>-&gt; Повернутися до ImgBed і ввести token та назву репозиторію</span></span>
<span class="line"><span>-&gt; Зберегти</span></span>
<span class="line"><span>-&gt; Якщо введено тільки назву repo, ImgBed автоматично додасть поточний username</span></span>
<span class="line"><span>-&gt; Якщо введено username/repo, ImgBed використає це як є</span></span>
<span class="line"><span>-&gt; ImgBed перевірить або створить dataset repository</span></span>
<span class="line"><span>-&gt; Завантажити тестове зображення</span></span></code></pre></div>`,18)])])}const k=d(o,[["render",r]]);export{b as __pageData,k as default};
